#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
	int solve(vector<int>& nums)
	{
		int count = 0;
		Stack<int> stack;
		for(int num : nums)
		{
			if (num != 0)
			{
				stack.push(num);
				count++;
			}
			else
			{
				if (!stack.empty())
				{
					stack.pop();
					count--;
				}
			}
		}
		return count;
	}
};
